(* keep *) wire [N_DELAY:0] w_delay_sig;
assign w_delay_sig[0] = i_data;
assign w_delay_sig[N_DELAY+1] = ~w_delay_sig[N_DELAY];

genvar i;
generate for (i = 0; i <= N_DELAY; i = i + 1) begin : delay_chain
  not n(w_delay_sig[i+1], w_delay_sig[i]);
end endgenerate

(* blackbox *)
module bb_not(input A, output Y);
endmodule

bb_not n(w_delay_sig[i], w_delay_sig[i+1]);
